  );
}

/* ────────────────────────────────────────────────────────
   ⑥ PHILOSOPHY — FULL-HEIGHT STICKY WITH SPLIT
      Left: image zooms, hue-rotates, caption changes
      Right: step list + animated detail card
──────────────────────────────────────────────────────── */
function Philosophy() {
  const wRef = useRef(null);
  const prog = useScrollProg(wRef);
  const active = Math.min(PHIL.length - 1, Math.floor(prog * PHIL.length));
  const cols = ['#0057ff', '#7c3aed', '#db2777', '#059669'];

  return (
    <div ref={wRef} style={{ height: `${100 + PHIL.length * 90}vh`, position: 'relative', background: '#f2f4f8' }}>
      <div style={{ position: 'sticky', top: 0, height: '100vh', overflow: 'hidden', display: 'flex', alignItems: 'center', borderTop: '1px solid var(--rule)' }}>
        <div className="wrap" style={{ width: '100%' }}>
          <div className="phil-grid" style={{ display: 'grid', gridTemplateColumns: '1fr', gap: 40 }}>

            {/* Left: morphing image */}
            <div className="phil-img" style={{ position: 'relative', borderRadius: 22, overflow: 'hidden', minHeight: 320 }}>
              <img src="https://images.unsplash.com/photo-1504384308090-c894fdcc538d?w=900&q=85" alt="Philosophy"
                style={{ width: '100%', height: '120%', objectFit: 'cover', transform: `scale(${1.08 + prog * .1}) translateY(${prog * -22}px)`, filter: `saturate(${.55 + prog * .5}) hue-rotate(${active * 28}deg)`, willChange: 'transform,filter', transition: 'none' }} />
              <div style={{ position: 'absolute', inset: 0, background: 'linear-gradient(to bottom,transparent 30%,rgba(4,11,24,.75))' }} />
              {/* Floating pill changes per step */}
              <div style={{ position: 'absolute', bottom: 22, left: 22, right: 22, background: 'rgba(255,255,255,.1)', backdropFilter: 'blur(18px)', border: '1px solid rgba(255,255,255,.18)', borderRadius: 14, padding: '16px 20px', transition: 'border-color .4s', borderColor: `rgba(${['0,87,255', '124,58,237', '219,39,119', '5,150,105'][active]},.4)` }}>
                <p style={{ fontSize: '.58rem', fontWeight: 700, letterSpacing: '.16em', textTransform: 'uppercase', color: 'rgba(255,255,255,.48)', marginBottom: 3 }}>Step {PHIL[active].n}</p>
                <p style={{ fontFamily: 'var(--serif)', fontSize: '1rem', fontWeight: 700, color: '#fff' }}>{PHIL[active].t}</p>
              </div>
            </div>

            {/* Right: step list + detail */}
            <div style={{ display: 'flex', flexDirection: 'column', justifyContent: 'center' }}>
              <Reveal><p style={{ fontSize: '.65rem', fontWeight: 700, letterSpacing: '.18em', textTransform: 'uppercase', color: 'var(--ink20)', marginBottom: 10 }}>Our Philosophy</p></Reveal>
              <CharStagger text="How We Think & Build" style={{ fontFamily: 'var(--serif)', fontSize: 'clamp(1.7rem,3.8vw,2.8rem)', fontWeight: 900, color: 'var(--ink)', letterSpacing: '-.025em', marginBottom: 28, lineHeight: 1.1 }} />

              <div style={{ display: 'flex', flexDirection: 'column', gap: 5, marginBottom: 24 }}>
                {PHIL.map(({ n, Icon, t }, i) => (
                  <div key={n} style={{ display: 'flex', alignItems: 'center', gap: 13, padding: '12px 16px', borderRadius: 13, transition: 'all .44s cubic-bezier(.16,1,.3,1)', background: active === i ? `rgba(${['0,87,255', '124,58,237', '219,39,119', '5,150,105'][i]},.07)` : 'transparent', border: active === i ? `1px solid rgba(${['0,87,255', '124,58,237', '219,39,119', '5,150,105'][i]},.22)` : '1px solid transparent', transform: active === i ? 'translateX(10px)' : 'none' }}>
                    <div style={{ width: 36, height: 36, borderRadius: 9, flexShrink: 0, display: 'flex', alignItems: 'center', justifyContent: 'center', transition: 'all .44s', background: active === i ? cols[i] : 'var(--rule)', color: active === i ? '#fff' : 'var(--ink40)' }}><Icon size={15} /></div>
                    <div>
                      <span style={{ fontSize: '.58rem', fontWeight: 700, letterSpacing: '.14em', textTransform: 'uppercase', color: active === i ? cols[i] : 'var(--ink20)', display: 'block', marginBottom: 1 }}>Step {n}</span>
                      <strong style={{ fontSize: '.92rem', color: active === i ? 'var(--ink)' : 'var(--ink40)', fontWeight: 700, transition: 'color .3s' }}>{t}</strong>
                    </div>
                    {active === i && <div style={{ marginLeft: 'auto', width: 7, height: 7, borderRadius: '50%', background: cols[i], flexShrink: 0 }} />}
                  </div>
                ))}
              </div>

              {/* Sliding detail card */}
              <Tilt style={{ background: '#fff', border: '1px solid #e2e8f0', borderRadius: 17, padding: '26px 28px', boxShadow: '0 6px 28px rgba(0,0,0,.06)' }}>
                <p style={{ fontSize: '.97rem', color: 'var(--ink60)', lineHeight: 1.88, marginBottom: 18 }}>{PHIL[active].d}</p>
                <div style={{ display: 'flex', gap: 6 }}>
                  {PHIL.map((_, pi) => (<div key={pi} style={{ height: 4, borderRadius: 2, transition: 'all .4s cubic-bezier(.16,1,.3,1)', background: pi === active ? cols[active] : '#e2e8f0', width: pi === active ? 32 : 8 }} />))}
                </div>
              </Tilt>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

/* ────────────────────────────────────────────────────────
   ⑦ TEAM CTA — parallax dark with aurora + scramble
──────────────────────────────────────────────────────── */
function TeamCta() {
  const ref = useRef(null);
  const [ty, setTy] = useState(0);
  const [vis, setVis] = useState(false);
  const [ioRef, inView] = useInView(.2);
  useEffect(() => {
    if (inView) setVis(true);
  }, [inView]);
  useEffect(() => {
    const fn = () => { if (!ref.current) return; const r = ref.current.getBoundingClientRect(); setTy((window.innerHeight - r.top) * .16); };
    window.addEventListener('scroll', fn, { passive: true });
    return () => window.removeEventListener('scroll', fn);
  }, []);
  return (
    <section ref={ref} style={{ position: 'relative', overflow: 'hidden', padding: '110px 0', background: '#020810', borderTop: '1px solid rgba(255,255,255,.05)' }}>
      <Aurora colors={['#0057ff', '#7c3aed', '#db2777']} opacity={.65} />
      <img src="https://images.unsplash.com/photo-1600880292203-757bb62b4baf?w=1600&q=75" alt="" aria-hidden style={{ position: 'absolute', inset: 0, width: '100%', height: '130%', objectFit: 'cover', opacity: .07, transform: `translateY(${ty}px)`, willChange: 'transform', transition: 'none' }} />
      <div style={{ position: 'absolute', inset: 0, background: 'linear-gradient(to bottom,rgba(2,8,16,.88),rgba(2,8,16,.55),rgba(2,8,16,.88))' }} />
      <div className="wrap" style={{ position: 'relative', zIndex: 1 }} ref={ioRef}>
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', flexWrap: 'wrap', gap: 44 }}>
          <Reveal dir="left" style={{ maxWidth: 600 }}>
            <p style={{ fontSize: '.65rem', fontWeight: 700, letterSpacing: '.18em', textTransform: 'uppercase', color: 'rgba(255,255,255,.3)', marginBottom: 14 }}>Leadership</p>
            <div style={{ fontFamily: 'var(--serif)', fontSize: 'clamp(2rem,5vw,3.8rem)', fontWeight: 900, color: '#fff', letterSpacing: '-.035em', marginBottom: 18, lineHeight: 1.06 }}>
              The Team Behind{' '}
              <ScrambleText text="Synnoviq" trigger={vis} style={{ color: '#5aa8ff', fontStyle: 'italic' }} />
            </div>
            <p style={{ fontSize: '.97rem', color: 'rgba(255,255,255,.44)', lineHeight: 1.9 }}>Deep technical expertise fused with strategic vision. Hands-on engineers who set the standard for quality on every engagement.</p>
          </Reveal>
          <Reveal dir="right">
            <Link to="/team" style={{ display: 'inline-flex', alignItems: 'center', gap: 10, padding: '17px 36px', borderRadius: 14, background: '#fff', color: '#020810', fontSize: '.96rem', fontWeight: 800, boxShadow: '0 4px 28px rgba(255,255,255,.1)', transition: 'all .25s' }}
              onMouseEnter={e => { e.currentTarget.style.background = '#0057ff'; e.currentTarget.style.color = '#fff'; e.currentTarget.style.transform = 'translateY(-4px)'; e.currentTarget.style.boxShadow = '0 14px 36px rgba(0,87,255,.55)'; }}
              onMouseLeave={e => { e.currentTarget.style.background = '#fff'; e.currentTarget.style.color = '#020810'; e.currentTarget.style.transform = ''; e.currentTarget.style.boxShadow = '0 4px 28px rgba(255,255,255,.1)'; }}>
              Meet the Team <ArrowRight size={17} />
            </Link>
          </Reveal>
        </div>
      </div>
    </section>
  );
}

